1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Customer {
14	  yearsWithMHPCO: number;
15	}
16	
17	interface Scenario {
18	  customer: Customer;
19	  steps: QuoteStep[];
20	}
21	
22	const MAIN_ITEM_BASE: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	};
28	
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	const COMPONENT_BASE = 25;
31	const BLOCK_SIZE = 3;
32	const BLOCK_BASE = 60;
33	
34	const PROCESSING_FEE = 5;
35	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
36	const CURSED_SURCHARGE_RATE = 0.5;
37	const HIGH_ENCHANTMENT_THRESHOLD = 5;
38	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
39	
40	const componentGroupBase = (count: number): number => {
41	  if (count === BLOCK_SIZE) return BLOCK_BASE;
42	  return count * COMPONENT_BASE;
43	};
44	
45	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
46	
47	const mainItems = (items: Item[]): Item[] => items.filter((item) => !isComponent(item));
48	
49	const sumMainItems = (items: Item[]): number =>
50	  mainItems(items).reduce((total, item) => total + MAIN_ITEM_BASE[item.type], 0);
51	
52	const countByType = (items: Item[]): Record<string, number> => {
53	  const counts: Record<string, number> = {};
54	  for (const item of items) {
55	    counts[item.type] = (counts[item.type] ?? 0) + 1;
56	  }
57	  return counts;
58	};
59	
60	const sumComponentGroups = (items: Item[]): number => {
61	  const counts = countByType(items.filter(isComponent));
62	  return Object.values(counts).reduce((total, count) => total + componentGroupBase(count), 0);
63	};
64	
65	const policyBasePremium = (items: Item[]): number =>
66	  sumMainItems(items) + sumComponentGroups(items);
67	
68	const itemSurcharges = (items: Item[]): number =>
69	  mainItems(items).reduce((total, item) => {
70	    const base = MAIN_ITEM_BASE[item.type];
71	    const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
72	    const highEnchantmentSurcharge =
73	      (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
74	        ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
75	        : 0;
76	    return total + cursedSurcharge + highEnchantmentSurcharge;
77	  }, 0);
78	
79	const quotePremium = (step: QuoteStep): number => {
80	  const base = policyBasePremium(step.items);
81	  const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE_RATE;
82	  return Math.ceil(withFirstInsurance + itemSurcharges(step.items)) + PROCESSING_FEE;
83	};
84	
85	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
86	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
87	  return { results };
88	};
